import{_ as a,o as t,c as o,ah as i}from"./chunks/framework.ojwJKwrc.js";const h=JSON.parse('{"title":"Simulator Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"internals/architecture.md","filePath":"internals/architecture.md"}'),n={name:"internals/architecture.md"};function s(l,e,r,c,d,g){return t(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="simulator-architecture" tabindex="-1">Simulator Architecture <a class="header-anchor" href="#simulator-architecture" aria-label="Permalink to &quot;Simulator Architecture&quot;">​</a></h1><p>Celox is an engine that generates JIT-compiled native code from Veryl RTL and executes cycle-based simulation.</p><h2 id="design-philosophy-and-target" tabindex="-1">Design Philosophy and Target <a class="header-anchor" href="#design-philosophy-and-target" aria-label="Permalink to &quot;Design Philosophy and Target&quot;">​</a></h2><p>This simulator is designed with the goal of <strong>maximizing verification efficiency for modern synchronous circuit designs (RTL)</strong>.</p><ul><li><strong>RTL-focused</strong>: Physical timing reproduction that trades off against simulation speed -- such as gate-level delays (# delays) and detailed delta-cycle behavior -- is intentionally simplified by restricting the design scope to RTL-level logic verification.</li><li><strong>Performance-first</strong>: Rather than interpreter-style emulation, the simulator compiles from SIR (Simulator IR) to native machine code to achieve execution throughput close to hand-written C.</li><li><strong>Consistency as a design goal</strong>: Mechanisms such as &quot;multi-phase evaluation&quot; and &quot;cascade clock detection&quot; have been designed and implemented to guarantee consistency for challenges encountered in real RTL designs, such as multi-clock domains and zero-delay clock trees. However, there are currently <a href="./cascade-limitations.html">race condition limitations under certain conditions</a>.</li></ul><h2 id="compilation-pipeline" tabindex="-1">Compilation Pipeline <a class="header-anchor" href="#compilation-pipeline" aria-label="Permalink to &quot;Compilation Pipeline&quot;">​</a></h2><p>The transformation from Veryl source code to execution consists of the following three major phases.</p><ol><li><p><strong>Frontend (Parser/Analyzer)</strong>:</p><ul><li>Parses Veryl source and generates the analyzer IR.</li><li><code>parser::parse_ir</code> takes this as input and converts each module into a <code>SimModule</code> (a struct containing SLT (logic expressions) and SIR (instruction sequences)).</li></ul></li><li><p><strong>Middle-end (Flattening/Scheduling/Optimization)</strong>:</p><ul><li><strong>Flattening</strong>: Flattens the instance hierarchy and converts module-local <code>VarId</code>s into global <code>AbsoluteAddr</code>s. Port connections are converted into <code>LogicPath</code>s.</li><li><strong>Atomization</strong>: Splits <code>LogicPath</code>s at bit boundaries (atoms) to analyze dependencies at bit-level precision.</li><li><strong>Scheduling</strong>: Topologically sorts the split atoms to determine the execution order of combinational logic. Detects SCCs via Tarjan&#39;s algorithm and handles cycles with static unrolling or dynamic convergence loops.</li><li><strong>SIR Optimization</strong>: Applies per-pass optimization (store-load forwarding, commit sinking, dead store elimination, instruction scheduling, etc.) controlled by <code>OptimizeOptions</code>.</li></ul></li><li><p><strong>Backend (Code Generation)</strong>:</p><ul><li><strong>Memory Layout</strong>: Determines memory offsets for all variables and places them on a single memory buffer with Stable, Working, Triggered-bits, and Scratch regions. Layout is pre-computed in <code>Program</code> after optimization, before backend codegen, so all backends share the same layout.</li><li><strong>Code Generation</strong>: Compiles SIR into executable machine code via one of the available backends.</li><li><strong>Runtime</strong>: Manages compiled function pointers as event handles and executes the simulation.</li><li><strong>Testbench VM</strong> (optional): A stack-based bytecode VM that executes Veryl <code>initial</code> blocks and testbench functions. Opcodes include <code>ConstU64</code>, <code>ConstWide</code>, <code>LoadU64</code>, <code>LoadWide</code>, <code>BinOp</code>, <code>UnaryOp</code>, <code>Ternary</code>, <code>LoadIndexed</code>, <code>LoadBitSelect</code>, <code>StoreU64</code>, supporting both narrow (≤64-bit) and wide signals.</li></ul></li></ol><h2 id="backends" tabindex="-1">Backends <a class="header-anchor" href="#backends" aria-label="Permalink to &quot;Backends&quot;">​</a></h2><p>Celox supports multiple compilation backends, selected at build time based on the target architecture.</p><h3 id="native-x86-64-backend-default" tabindex="-1">Native x86-64 Backend (Default) <a class="header-anchor" href="#native-x86-64-backend-default" aria-label="Permalink to &quot;Native x86-64 Backend (Default)&quot;">​</a></h3><p>The self-hosted native backend is the default on x86-64 platforms. It compiles SIR through a dedicated pipeline:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SIR (bit-level)</span></span>
<span class="line"><span>  → ISel (Instruction Selection)</span></span>
<span class="line"><span>    → MIR (word-level SSA with VRegs)</span></span>
<span class="line"><span>      → mir_opt (MIR optimization passes)</span></span>
<span class="line"><span>        → regalloc (Braun &amp; Hack MIN algorithm)</span></span>
<span class="line"><span>          → emit (x86-64 machine code via iced-x86)</span></span></code></pre></div><p>Key features of the native backend:</p><ul><li><strong>MIR</strong>: A word-level SSA IR with virtual registers (<code>VReg</code>). Instructions operate on 64-bit values; bit-level access information is preserved in <code>SpillDesc</code> side-tables for cost-aware spill decisions.</li><li><strong>MIR Optimization</strong>: Constant folding, copy propagation, algebraic simplification, GVN, DCE, if-conversion (Branch → Select/cmov), CFG simplification, PEXT fusion for XOR chains, and more. An adaptive pipeline runs the full pass set iteratively for high-pressure functions (VRegs &gt; 40) and a lightweight variant for small functions.</li><li><strong>Register Allocator</strong>: A unified single-pass allocator based on the Braun &amp; Hack (2009) extended MIN algorithm. Performs simultaneous spilling and assignment in one forward pass with cost-aware eviction. Supports three spill kinds: SimState (reload from simulation memory), Stack, and Remat (rematerialize immediates).</li><li><strong>EU Merge</strong>: Multiple execution units are merged into a single function with shared prologue/epilogue and <code>jmp</code>-linked boundaries, reducing call overhead.</li><li><strong>Cmp+Branch Fusion</strong>: When a comparison result only feeds a branch, the <code>setcc</code>+<code>movzx</code>+<code>test</code> sequence is replaced by a direct <code>cmp</code>+<code>jcc</code>.</li></ul><h3 id="cranelift-backend-fallback" tabindex="-1">Cranelift Backend (Fallback) <a class="header-anchor" href="#cranelift-backend-fallback" aria-label="Permalink to &quot;Cranelift Backend (Fallback)&quot;">​</a></h3><p>The Cranelift-based JIT backend (<code>JitBackend</code>) remains available for non-x86-64 targets and as a fallback. It compiles SIR directly to native code via <a href="https://cranelift.dev/" target="_blank" rel="noreferrer">Cranelift</a>. Cranelift-specific options (<code>CraneliftOptLevel</code>, <code>RegallocAlgorithm</code>, <code>enable_alias_analysis</code>, <code>enable_verifier</code>) are configured through <code>CraneliftOptions</code>.</p><h3 id="wasm-backend" tabindex="-1">WASM Backend <a class="header-anchor" href="#wasm-backend" aria-label="Permalink to &quot;WASM Backend&quot;">​</a></h3><p>A WebAssembly backend (<code>wasm_codegen</code>) generates WASM bytecode from SIR. The Rust-side <code>WasmBackend</code> instantiates that bytecode via wasmtime, while the TypeScript playground path exposes the same generated bytes and runs them through the browser&#39;s WebAssembly APIs.</p><h3 id="backend-trait" tabindex="-1">Backend Trait <a class="header-anchor" href="#backend-trait" aria-label="Permalink to &quot;Backend Trait&quot;">​</a></h3><p>All backends implement the <code>SimBackend</code> trait, which provides a unified interface for:</p><ul><li>Combinational evaluation (<code>eval_comb</code>)</li><li>Single-phase FF evaluation (<code>eval_apply_ff_at</code>) — fast path when a step can use combined evaluate+apply semantics</li><li>Split-phase FF evaluation (<code>eval_only_ff_at</code>, <code>apply_ff_at</code>) — for cascade clock consistency</li><li>Signal/event access (<code>resolve_signal</code>, <code>resolve_event</code>, <code>resolve_event_opt</code>, <code>resolve_eval_only_event</code>, <code>resolve_apply_event</code>)</li><li>Get/set operations (<code>get</code>, <code>set</code>, <code>set_wide</code>, <code>get_four_state</code>, <code>set_four_state</code>)</li><li>Memory/layout access (<code>memory_as_ptr</code>, <code>memory_as_mut_ptr</code>, <code>stable_region_size</code>, <code>layout</code>)</li><li>Triggered-bits management (<code>clear_triggered_bits</code>, <code>mark_triggered_bit</code>, <code>get_triggered_bits</code>)</li></ul><h2 id="memory-model" tabindex="-1">Memory Model <a class="header-anchor" href="#memory-model" aria-label="Permalink to &quot;Memory Model&quot;">​</a></h2><p>The simulator employs a <strong>multi-region model on a single memory buffer</strong>.</p><ul><li><strong>Stable region</strong>: Holds the current committed values. Combinational logic inputs and outputs reference this region.</li><li><strong>Working region</strong>: Temporarily holds the next state of flip-flops. Only variables that are actually written have Working region slots allocated.</li><li><strong>Triggered-bits region</strong>: One bit per event, used for cascade/gated clock trigger detection. After a <code>Store</code> instruction, the backend compares old and new values and sets the corresponding trigger bit if changed.</li><li><strong>Scratch region</strong>: Used by the tail-call splitting pass for inter-chunk register value spilling.</li><li><strong>SignalRef</strong>: A handle that caches offsets and metadata, enabling direct memory access without going through a <code>HashMap</code>.</li><li><strong>Address Aliases</strong>: The <code>IdentityStoreBypass</code> optimization detects variables that are identity copies (Store→Load roundtrips) and registers them as aliases in <code>Program::address_aliases</code>. Aliased variables share physical memory, eliminating redundant copies.</li></ul><p>For 4-state variables, each variable occupies <code>2 × ceil(width/8)</code> bytes (value + mask pair).</p><h2 id="execution-control-logic" tabindex="-1">Execution Control Logic <a class="header-anchor" href="#execution-control-logic" aria-label="Permalink to &quot;Execution Control Logic&quot;">​</a></h2><p><code>Simulation::step</code> advances the simulation time by one step using the following flow.</p><ol><li><strong>Event extraction</strong>: Retrieves all events occurring at the current time (such as clock changes) from the scheduler.</li><li><strong>Clock edge detection</strong>: <ul><li>Previous values are retained in a <code>BitSet</code> and compared with the updated values to determine <code>posedge</code> / <code>negedge</code>.</li><li>Based on <code>DomainKind</code>, checks whether the target flip-flop groups have been triggered.</li></ul></li><li><strong>Silent edge skipping</strong>: When a signal value has changed but the flip-flop trigger condition is not met (e.g., a falling edge when a rising edge is specified), unnecessary flip-flop evaluation is skipped.</li><li><strong>Multi-phase evaluation</strong>: <ul><li>When multiple domains are triggered simultaneously, to maintain consistency as an event-driven model, next-state computation via <code>eval_only</code> is first performed across all domains. Then, after all computations are complete, values are written to the Stable region all at once via <code>apply</code>. This avoids value inconsistencies between simultaneously occurring events.</li></ul></li><li><strong>Cascade clock detection</strong>: <ul><li>To handle cases where a flip-flop output serves as the clock for another flip-flop (zero-delay clock tree), clock signal changes are re-scanned after domain evaluation, and evaluation is repeated until the state stabilizes.</li></ul></li></ol><h2 id="related-components" tabindex="-1">Related Components <a class="header-anchor" href="#related-components" aria-label="Permalink to &quot;Related Components&quot;">​</a></h2><ul><li><strong><code>SimBackend</code></strong>: Trait abstracting over compilation backends. <code>NativeBackend</code> (x86-64), <code>JitBackend</code> (Cranelift), and <code>WasmBackend</code> (wasmtime) implement this trait.</li><li><strong><code>Scheduler</code></strong>: Manages events using a <code>BinaryHeap</code> and dispatches them in chronological order with deterministic ordering (time → event ID → signal).</li><li><strong><code>VcdWriter</code></strong>: Records signal changes during simulation in VCD format.</li><li><strong><code>MemoryLayout</code></strong>: Pre-computed offset map shared by all backends. Contains stable/working region offsets, variable widths, 4-state flags, triggered-bits region, and scratch region for inter-chunk spilling.</li></ul>`,31)])])}const u=a(n,[["render",s]]);export{h as __pageData,u as default};
